	}

	state := newTestStateFromRecords(t, nil) // no managed instances -> kas_orphan is orphan

	err := executeTmuxKill(state, "kas_orphan", m)
	require.Error(t, err)
	assert.Contains(t, err.Error(), "kill tmux session kas_orphan")
	assert.ErrorIs(t, err, killErr)
}

