func TestTmuxAdopt_StateJSONRoundtrip(t *testing.T) {
	epoch := int64(1741084800)
	orphanLine := fakeTmuxLine("kas_roundtrip", epoch, 1, false, 200, 40)
	now := time.Date(2026, 3, 4, 12, 0, 0, 0, time.UTC)

	exec := mockExecOutput(orphanLine)

