	err := executeTmuxAdopt(state, "kas_roundtrip", "roundtrip-adopted", "/repo", now, exec)
	require.NoError(t, err)

	// Re-read state and verify the raw JSON preserved all keeper fields.
	raw := state.GetInstances()
